B.a76=new A.mM("\ud83c\uddfa\ud83c\uddf8","Estados Unidos","NPR \u2013 National Public Radio",'\ud83c\udf99\ufe0f Curiosidade: O sotaque americano padr\xe3o (General American) \xe9 o mais ensinado no mundo por ser neutro e claro. Repare na pron\xfancia do "R" forte no final das palavras (ex: "car", "water"). Voc\xea encontrar\xe1 entrevistas, document\xe1rios e not\xedcias com fala precisa \u2014 ideal para iniciantes e intermedi\xe1rios.',"https://npr-ice.streamguys1.com/live.mp3",B.p0)
B.Hp=new A.C(1,0.7764705882352941,0.1568627450980392,0.1568627450980392,B.e)
B.a75=new A.mM("\ud83c\uddec\ud83c\udde7","Reino Unido","BBC World Service",'\ud83c\udf99\ufe0f Curiosidade: O sotaque brit\xe2nico RP (Received Pronunciation) \xe9 famoso por "engolir" o R no meio das palavras \u2014 "car" vira "cah". Tamb\xe9m usam vocabul\xe1rio \xfanico: "lift" (elevador), "flat" (apartamento), "lorry" (caminh\xe3o). Excelente para treinar ingl\xeas formal e expandir vocabul\xe1rio.',"https://stream.live.vc.bbcmedia.co.uk/bbc_world_service",B.Hp)
B.Hx=new A.C(1,0.7176470588235294,0.10980392156862745,0.10980392156862745,B.e)
B.a73=new A.mM("\ud83c\udde8\ud83c\udde6","Canad\xe1","CKNW 980 \u2013 News Talk Vancouver",'\ud83c\udf99\ufe0f Curiosidade: O canadense tem o fen\xf4meno chamado "Canadian Raising" \u2014 as vogais em palavras como "about" e "house" soam diferente do americano, quase como "aboot". Fora isso, misturam vocabul\xe1rio brit\xe2nico e americano. \xd3timo para distinguir sutilezas do ingl\xeas norte-americano.',"https://live.leanstream.co/CKNWAM-MP3",B.Hx)
B.ow=new A.C(1,0.10588235294117647,0.3686274509803922,0.12549019607843137,B.e)
B.a74=new A.mM("\ud83c\udde6\ud83c\uddfa","Austr\xe1lia","ABC News Radio",'\ud83c\udf99\ufe0f Curiosidade: O australiano transforma vogais longas \u2014 "today" soa como "to-die", "mate" quase como "mite". Eles tamb\xe9m adoram encurtar palavras: "afternoon" vira "arvo", "biscuit" vira "biccy". Um desafio real para o ouvido! Ideal para alunos que querem se preparar para situa\xe7\xf5es do mundo real.',"https://live-radio01.mediahubaustralia.com/PBW/mp3/",B.ow)
B.a71=new A.mM("\ud83c\uddee\ud83c\uddea","Irlanda","RT\xc9 Radio 1",'\ud83c\udf99\ufe0f Curiosidade: O irland\xeas tem uma musicalidade \xfanica herdada do ga\xe9lico \u2014 a entona\xe7\xe3o sobe e desce diferente de qualquer outro sotaque. Palavras como "film" podem soar como "fillum" e o "th" \xe0s vezes vira "t" ou "d". Voc\xea encontrar\xe1 debates culturais, humor e uma riqueza de express\xf5es idiom\xe1ticas t\xedpicas da ilha.',"https://icecast2.rte.ie/radio1",B.oK)
